sys_script_include.script:
var IncentNowRuleClientUtils = Class.create();
IncentNowRuleClientUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {


    getOperators: function() {
        var mappingSysId = this.getParameter('sysparm_mapping_field');
        if (!mappingSysId)
            return JSON.stringify([]);

        var fieldType = this._getFieldType(mappingSysId);
        var operators = this._buildOperatorList(fieldType);

        return JSON.stringify(operators);
    },

    _getFieldType: function(mappingSysId) {
        var mappingGR = new GlideRecordSecure('x_ctans_incentnow_metadata_mapping'); //  mapping table
        if (!mappingGR.get(mappingSysId))
            return '';

        if (mappingGR.field_type)
            return mappingGR.field_type.name.toString(); // derived field type

        return '';
    },

    _buildOperatorList: function(fieldType) {
        var operators = [];

        switch (fieldType) {

            case 'integer':
            case 'decimal':
            case 'currency':
                operators = [
                    { value: '=', label: 'Is' },
                    { value: '!=', label: 'Is not' },
                    { value: '>', label: 'Greater than' },
                    { value: '<', label: 'Less than' },
                    { value: '>=', label: 'Greater than or is' },
                    { value: '<=', label: 'Less than or is' }
                ];
                break;

            case 'string':
                operators = [
                    { value: '=', label: 'Is' },
                    { value: '!=', label: 'Is not' },
                    { value: 'LIKE', label: 'Contains' },
                    { value: 'STARTSWITH', label: 'Starts with' },
                    { value: 'ENDSWITH', label: 'Ends with' }
                ];
                break;

            case 'datetime':
            case 'glide_date_time':
                operators = [
                    { value: 'ON', label: 'On' },
                    { value: 'NOTON', label: 'Not on' },
                    { value: '>', label: 'After' },
                    { value: '<', label: 'Before' },
                   // { value: 'BETWEEN', label: 'Between' }
                ];
                break;
        }

        return operators;
    },

    type: 'IncentNowRuleClientUtils'
});
